class Solution(object):
    def numberOfSubarrays(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        n = len(nums)
        result = 0

        # For each position, use monotonic stack to find where it's maximum
        stack = []  # Monotonic decreasing stack

        for i in range(n):
            # Remove elements smaller than current
            while stack and stack[-1][0] < nums[i]:
                stack.pop()

            stack.append((nums[i], i))

            # Find left boundary: nearest position to left where nums[j] > nums[i]
            # This is done by checking stack
            left_bound = 0
            if len(stack) > 1:
                # If current is same as previous in stack, use prev's left bound
                temp_stack = []
                for j in range(len(stack) - 1):
                    if stack[j][0] >= stack[-1][0]:
                        temp_stack.append(stack[j])

                if temp_stack:
                    left_bound = temp_stack[-1][1] + 1

            # Simpler approach: for each i, find nearest j on left where nums[j] > nums[i]
            j = i - 1
            while j >= 0 and nums[j] <= nums[i]:
                j -= 1

            left_bound = j + 1

            # Find subarrays [l, r] where l >= left_bound, r >= i, nums[l] == nums[r] == max
            for l in range(left_bound, i + 1):
                if nums[l] == nums[i]:
                    result += 1

        return result
